    public partial class EmpBonusService : BaseService<EmpBonus>, IEmpBonusService
    {
        public EmpBonusService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task<EmpBonus> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<EmpBonus>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.Employee),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IPaginate<EmpBonus>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<EmpBonus>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Employee.Name.Contains(search.Name)),
                include: i => i.Include(x => x.Employee),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Employee.Name", ascending: !search.IsDescend);
        }
    }
